INSERT INTO app_community_post (
    user_id, content, source_type, status, open_comments
) VALUES (
    #{userId}, #{content}, #{sourceType}, #{status}, COALESCE(#{openComments}, 1)
)

INSERT INTO app_community_post_media (
    post_id, user_id, media_key, storage_provider, media_url_snapshot, media_type, sort_order
) VALUES (
    #{postId}, #{userId}, #{mediaKey}, #{storageProvider}, #{mediaUrlSnapshot}, #{mediaType}, #{sortOrder}
)

mapper.select:
SELECT COUNT(1)
FROM app_community_post p



        AND EXISTS (
            SELECT 1
            FROM app_community_follow ff
            WHERE ff.from_user_id = #{viewerId}
              AND ff.to_user_id = p.user_id
        )


        AND p.user_id = #{userId}

SELECT
FROM app_community_post p LEFT JOIN app_user u ON u.id = p.user_id LEFT JOIN app_h5_user_profile_ext ext ON ext.user_id = p.user_id LEFT JOIN app_community_like l ON l.post_id = p.id AND l.user_id = #{viewerId} LEFT JOIN app_community_follow f ON f.from_user_id = #{viewerId} AND f.to_user_id = p.user_id LEFT JOIN app_social_friend sf ON sf.user_id = #{viewerId} AND sf.friend_user_id = p.user_id AND sf.status = 'normal' AND sf.deleted_at IS NULL LEFT JOIN app_social_friend_request fr ON fr.requester_user_id = #{viewerId} AND fr.target_user_id = p.user_id AND fr.status = 'pending' LEFT JOIN app_social_friend_request inbound_fr ON inbound_fr.requester_user_id = p.user_id AND inbound_fr.target_user_id = #{viewerId} AND inbound_fr.status = 'pending'
AND EXISTS ( SELECT 1 FROM app_community_follow ff WHERE ff.from_user_id = #{viewerId} AND ff.to_user_id = p.user_id )
AND p.user_id = #{userId}
ORDER BY p.created_at DESC, p.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT post_id AS postId, id AS id, media_key AS mediaKey, media_url_snapshot AS mediaUrl, storage_provider AS storageProvider, media_type AS mediaType, sort_order AS sortOrder FROM app_community_post_media WHERE post_id IN
#{postId}
ORDER BY post_id ASC, sort_order ASC, id ASC

